import React, { useEffect, useRef } from 'react';

const VideoFrame = ({ src, onError }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (src && containerRef.current) {
      // Crear iframe de forma muy básica para evitar detección
      const frame = document.createElement('iframe');

      // Solo atributos esenciales
      frame.src = src;
      frame.width = '100%';
      frame.height = '100%';
      frame.allowFullscreen = true;

      // Estilos para ocultar elementos no deseados
      frame.style.cssText = `
        border: none;
        background: #000;
        border-radius: 8px;
        width: 100%;
        height: 100%;
        transform: scale(1.2);
        transform-origin: center;
        overflow: hidden;
      `;

      // Limpiar y agregar
      containerRef.current.innerHTML = '';
      containerRef.current.appendChild(frame);

      // Inyectar CSS para ocultar elementos de Streamtape
      frame.onload = () => {
        try {
          const doc = frame.contentDocument || frame.contentWindow.document;
          if (doc) {
            const style = doc.createElement('style');
            style.textContent = `
              .header, .footer, .sidebar, .ads, .info, .embed-code,
              [class*="ad"], [id*="ad"], .advertisement,
              .streamtape-info, .file-info, .embed-info {
                display: none !important;
              }
              body {
                margin: 0 !important;
                padding: 0 !important;
                overflow: hidden !important;
              }
              video {
                width: 100% !important;
                height: 100% !important;
              }
            `;
            doc.head.appendChild(style);
          }
        } catch (e) {
          // Error de CORS es normal
          console.log('No se pudo inyectar CSS (CORS)');
        }
      };

      // Verificar si carga
      const checkLoad = setTimeout(() => {
        try {
          if (!frame.contentWindow) {
            console.log('Iframe no cargó correctamente');
            if (onError) onError();
          }
        } catch (e) {
          console.log('Error verificando iframe:', e.message);
          if (onError) onError();
        }
      }, 5000);

      return () => {
        clearTimeout(checkLoad);
        if (containerRef.current) {
          containerRef.current.innerHTML = '';
        }
      };
    }
  }, [src, onError]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-96 md:h-[500px] lg:h-[600px] bg-black rounded-lg overflow-hidden"
      style={{ 
        minHeight: '400px',
        position: 'relative'
      }}
    />
  );
};

export default VideoFrame;
